SELECT COUNT(indicator_id) AS NumberOfIndicators
FROM indicator_versions
WHERE is_current = 1;

SELECT DISTINCT users.user_name
FROM users
INNER JOIN indicator_comments ON users.user_id = indicator_comments.user_id;

SELECT COUNT(*)
FROM regions
WHERE area_km2 > (SELECT AVG(area_km2) FROM regions);

SELECT indicators.indicator_id, indicator_values.value
FROM indicators
JOIN indicator_values ON indicators.indicator_id = indicator_values.indicator_id;

SELECT indicator_name
FROM indicators
ORDER BY indicator_name ASC;
